PROFILES = load_profiles("profiles/*.yaml")

function handle(query):
    candidate   = router.classify(query, profiles=list(PROFILES))
    profile     = resolve(candidate)

    # Verifier sees the query AND the chosen profile's persona/motivator;
    # it returns {accept | reroute | escalate} with a reason.
    verdict = verifier.judge(
        query=query,
        profile_summary=summarise(profile),
        alternatives=[p.id for p in PROFILES.values() if p.id != candidate],
    )
    if verdict.kind == "reroute":
        candidate = verdict.suggested_profile
        profile   = resolve(candidate)
        tracer.emit("route.reroute", from_=candidate, to=verdict.suggested_profile,
                    reason=verdict.reason)
    elif verdict.kind == "escalate":
        return human_handoff(query, reason=verdict.reason)

    specialists = {pid: agent_for(resolve(pid)) for pid in PROFILES}
    return specialists[candidate].handle(
        query,
        system_prompt=compose_prompt(profile),
        tools=profile.action_set,
        memory=profile.knowledge_bindings.memory_partitions,
    )

