# Dispatcher routes each service task to its handler.
function execute_service_task(node, ctx):
    route   = router.classify(node, choices=["deterministic", "agent"])
    if route == "deterministic":
        return deterministic_handlers[node.id](ctx)

    # Agent handler: bounded scope, typed I/O contract.
    specialists = {
        "summarise_explanation": summary_agent,
        "resolve_free_text":    intake_agent,
    }
    result = specialists[node.id].handle(
        input=ctx.slice(node.input_schema),
        schema=node.output_schema,    # must validate before returning
    )
    return validate(result, node.output_schema)

function run(case):
    return bpmn_engine.run(
        process="loan-application",
        case=case,
        service_executor=execute_service_task,
    )

# Why this works: BPMN keeps step-level observability and DMN keeps
# decision auditability; the LLM is a typed plug-in at clearly marked
# nodes so the agent's flexibility never leaks into the spine.
# Related: see `hybrid-symbolic-neural-routing`.

# Related: policy-gated-agent-action
function execute_service_task(node, ctx):
    if node.type != "unstructured":
        return deterministic_handlers[node.id](ctx)

    # Policy gate: DMN table maps (risk_class, data_class, tenant) -> allowed_agents
    policy = dmn_engine.evaluate(
        table="agent-policy",
        inputs={"risk_class":  ctx.risk_class,
                "data_class":  ctx.data_class,
                "tenant":      ctx.tenant_id,
                "node":        node.id},
    )
    if not policy.allowed_agents:
        tracer.emit("policy.deny", node=node.id, reason=policy.reason)
        return deterministic_fallbacks[node.id](ctx)   # safe-path

    route = router.classify(node, choices=policy.allowed_agents)
    specialists = {"summary": summary_agent,
                   "intake":  intake_agent,
                   "draft":   draft_agent}
    result = specialists[route].handle(
        input=ctx.slice(node.input_schema),
        schema=node.output_schema,
    )
    return validate(result, node.output_schema)

function run(case):
    return bpmn_engine.run("loan-application", case=case,
                           service_executor=execute_service_task)

