STATE        = "closed"     # closed | open | half_open
failures     = rolling_window(size=N)
opened_at    = null
THRESHOLD    = 0.5          # 50% error rate over the window
COOLDOWN     = 30           # seconds

function call(dep, request):
    global STATE, opened_at

    if STATE == "open":
        if now() - opened_at < COOLDOWN:
            return fallback(request)   # fail fast, no remote call
        STATE = "half_open"            # one trial call allowed

    try:
        result = dep.invoke(request)
        failures.record(ok=true)
        if STATE == "half_open":
            STATE = "closed"           # trial succeeded — close breaker
        return result
    except Error as e:
        failures.record(ok=false)
        if STATE == "half_open" or failures.error_rate() > THRESHOLD:
            STATE = "open"
            opened_at = now()
        return fallback(request)

# Related: kill-switch, degenerate-output-detection
STATE = "closed"
failures  = rolling_window(size=N)
opened_at = null
THRESHOLD = 0.5
COOLDOWN  = 30

function call(dep, request):
    global STATE, opened_at
    if killswitch.is_set(dep.id):
        tracer.emit("killswitch.open", dep=dep.id)
        return fallback(request)
    if STATE == "open":
        if now() - opened_at < COOLDOWN:
            return fallback(request)
        STATE = "half_open"
    try:
        result = dep.invoke(request)
        # Treat degenerate outputs as failures, not successes.
        verdict = degenerate_detector.judge(result)
        if verdict.is_degenerate:
            failures.record(ok=false)
            tracer.emit("dep.degenerate", dep=dep.id, kind=verdict.kind)
            if STATE == "half_open" or failures.error_rate() > THRESHOLD:
                STATE = "open"; opened_at = now()
            return fallback(request)
        failures.record(ok=true)
        if STATE == "half_open":
            STATE = "closed"
        return result
    catch Error as e:
        failures.record(ok=false)
        if STATE == "half_open" or failures.error_rate() > THRESHOLD:
            STATE = "open"; opened_at = now()
        return fallback(request)

# Why this works: the breaker trips on quality regressions as well as transport
# errors, so a vendor that goes silently bad (repeated empty/loop output) is
# detected; the kill-switch gives operators an immediate global override.
# Related: see `kill-switch`, `degenerate-output-detection`.

HANDLERS = [
    primary_handler,        # fast, narrow, high precision
    secondary_handler,      # broader, slower, lower precision
    tertiary_handler,       # very broad, weakest signal
]

TERMINAL = lambda req: Answer(
    text="I don't have a confident answer for that.",
    confidence=1.0,         # confidently refusing IS the answer
)

function handle(request):
    for h in HANDLERS:
        try:
            out = h(request)
            if out.confidence >= THRESHOLD:
                return out
        except HandlerError:
            continue        # fall through to next handler
    return TERMINAL(request)

from datetime import timedelta
from temporalio import workflow
from temporalio.common import RetryPolicy


@workflow.defn
class AnswerWorkflow:
    @workflow.run
    async def run(self, question: str) -> str:
        # Primary activity — bounded retries with backoff form the
        # first step of the fallback chain.
        try:
            return await workflow.execute_activity(
                "ask_primary_model",
                question,
                start_to_close_timeout=timedelta(seconds=30),
                retry_policy=RetryPolicy(
                    initial_interval=timedelta(seconds=1),
                    backoff_coefficient=2.0,
                    maximum_attempts=3,
                ),
            )
        except Exception:
            # Fallback activity — different provider / cheaper model.
            try:
                return await workflow.execute_activity(
                    "ask_fallback_model",
                    question,
                    start_to_close_timeout=timedelta(seconds=30),
                    retry_policy=RetryPolicy(maximum_attempts=2),
                )
            except Exception:
                # Terminal: confident refusal, not a wrong answer.
                return "I don't have a confident answer for that."

DEGRADED = {
    "vision":     "text_only",
    "retrieval":  "no_citations",
    "code_exec":  "plain_summary",
}

function respond(request):
    features = required_features(request)
    notices  = []

    for f in features:
        if not health.ok(f):
            request.mode[f] = DEGRADED[f]
            notices.append(
                disclosure(f, DEGRADED[f])     # tell the user
            )

    answer = run_pipeline(request)             # only healthy deps used
    return assemble(answer, notices=notices)

# Each feature has a chain of variants, ordered from full to degraded.
FEATURE_CHAIN = {
    "vision":    ["vision.full",    "vision.captions",  "text_only"],
    "retrieval": ["rag.cited",      "rag.summarised",   "no_citations"],
    "code_exec": ["sandbox.full",   "sandbox.dry_run",  "plain_summary"],
}
BUDGET_MS = {"vision.full": 4000, "rag.cited": 2500, "sandbox.full": 5000}

function respond(request):
    features = required_features(request)
    chosen, notices = {}, []

    for f in features:
        for variant in FEATURE_CHAIN[f]:
            t0 = now()
            if not health.ok(variant):
                tracer.emit("feature.skip", feature=f, variant=variant)
                continue
            try:
                with budget_guard(latency_ms=BUDGET_MS.get(variant, 1000)):
                    chosen[f] = run_variant(variant, request)
                tracer.emit("feature.ok", feature=f, variant=variant,
                            latency_ms=now()-t0)
                if variant != FEATURE_CHAIN[f][0]:
                    notices.append(disclosure(f, variant))
                break
            catch (DepError, BudgetExceeded) as e:
                tracer.emit("feature.fallback", feature=f, variant=variant,
                            reason=type(e).name, latency_ms=now()-t0)
                continue
        else:
            notices.append(disclosure(f, "unavailable"))

    return assemble(run_pipeline(request, chosen), notices=notices)

# Why this works: degradation triggers on budget overrun as well as on outage,
# so a slow-but-up dep does not stall the user, and the disclosure carries a
# stable variant id the client can render and the audit log can group on.
# Related: see `fallback-chain`, `circuit-breaker`.

SYMBOLIC = RuleEngine(rules=TAX_RULES, ontology=ONTOLOGY)
NEURAL   = LLMAgent(model="frontier", retriever=RAG, tools=TOOLS)

function route(query):
    kind = router.classify(query)   # "symbolic" | "neural" | "hybrid"

    if kind == "symbolic":
        # Hard rule satisfaction — exact, verifiable execution.
        return SYMBOLIC.evaluate(query)

    if kind == "neural":
        # Free-text interpretation — no exact rules apply.
        return NEURAL.answer(query)

    # Hybrid: LLM proposes a plan, symbolic layer validates + runs it.
    plan = NEURAL.propose_plan(query)
    if not SYMBOLIC.validates(plan):
        return refuse(reason="plan violates constraints")
    result = SYMBOLIC.execute(plan)

    # Track router accuracy as a first-class metric — boundary drift
    # is a regression, not a free move.
    metrics.record(query, kind, result, ground_truth=judge.score(result))
    return result

specialists = {
    "symbolic": RuleEngine(rules=DOMAIN_RULES, ontology=ONTOLOGY),
    "neural":   LLMAgent(model="frontier", retriever=RAG, tools=TOOLS),
}

function handle(query):
    route = router.classify(query)    # "symbolic" | "neural" | "hybrid"

    if route == "symbolic":
        return specialists["symbolic"].evaluate(query)

    if route == "neural":
        return specialists["neural"].answer(query)

    # Hybrid: LLM proposes a plan, symbolic layer validates and runs it.
    plan = specialists["neural"].propose_plan(query)
    if not specialists["symbolic"].validates(plan):
        return refuse(reason="plan_violates_constraints")
    result = specialists["symbolic"].execute(plan)

    # Router accuracy is a first-class metric; boundary drift is a
    # regression, not a free move.
    metrics.record(query=query, route=route, result=result,
                   ground_truth=judge.score(result))
    return result

# Why this works: exact constraints stay where they can be verified, and
# free-text interpretation stays where the LLM is good; the hybrid path
# combines them without ever letting the LLM assert the answer alone.
