# Each expert is deeply specialised — bespoke system prompt and
# a narrow tool palette, possibly a fine-tuned model.
EXPERTS = {
    "legal":     Agent(prompt=LEGAL_PROMPT,    tools=LEGAL_TOOLS),
    "medical":   Agent(prompt=MEDICAL_PROMPT,  tools=MEDICAL_TOOLS),
    "finance":   Agent(prompt=FINANCE_PROMPT,  tools=FINANCE_TOOLS),
    "code":      Agent(prompt=CODE_PROMPT,     tools=CODE_TOOLS),
}

function route(request):
    scores = router_model.score_domains(
        request,
        labels=list(EXPERTS.keys()),
    )
    top = scores.top_k(k=2, min_score=0.4)

    if len(top) == 0:
        return generalist.answer(request)
    if len(top) == 1:
        return EXPERTS[top[0].label].answer(request)

    # Multiple domains relevant — fan out and aggregate.
    outputs = parallel_map(
        lambda label: EXPERTS[label].answer(request),
        [t.label for t in top],
    )
    return aggregator.merge(outputs, weights=top.scores)

# Each expert ships with its own per-call budget; aggregator weights too.
EXPERTS = {
    "legal":   Specialist(agent=LEGAL_AGENT,   budget_ms=6000, cost_usd=0.08),
    "medical": Specialist(agent=MEDICAL_AGENT, budget_ms=6000, cost_usd=0.08),
    "finance": Specialist(agent=FINANCE_AGENT, budget_ms=4000, cost_usd=0.05),
    "code":    Specialist(agent=CODE_AGENT,    budget_ms=5000, cost_usd=0.06),
}

function route(request):
    scores = router_model.score_domains(request, labels=list(EXPERTS))
    top    = scores.top_k(k=2, min_score=0.4)

    if len(top) == 0:
        tracer.emit("route.generalist", reason="no_domain_match")
        return generalist.answer(request)

    function try_expert(label):
        s = EXPERTS[label]
        t0 = now()
        try:
            with budget_guard(latency_ms=s.budget_ms, cost_usd=s.cost_usd):
                out = s.agent.answer(request)
            tracer.emit("expert.ok", expert=label, latency_ms=now()-t0)
            return out
        catch (ExpertRefused, ProviderError, BudgetExceeded) as e:
            tracer.emit("expert.fallback", expert=label, reason=type(e).name)
            return null

    if len(top) == 1:
        return try_expert(top[0].label) or generalist.answer(request)

    outputs = [o for o in parallel_map(try_expert, [t.label for t in top]) if o]
    if not outputs:
        return generalist.answer(request)
    tracer.emit("expert.aggregate", experts=[t.label for t in top])
    return aggregator.merge(outputs, weights=top.scores)

# Why this works: each expert is bounded so one slow specialist cannot stall
# the request; if every expert refuses or errors the generalist takes over,
# and every route choice and aggregation is auditable per-expert.
# Related: see `fallback-chain`, `complexity-based-routing`.

# Related: verification-of-route-choice
specialists = {
    "calc":     CalculatorModule(),
    "kb_sql":   SQLKnowledgeBase(conn=DB),
    "code":     PythonSandbox(),
    "weather":  WeatherAPISpecialist(),
    "medical":  MedicalQAModel(),
}

function handle(query):
    plan = router.classify(query, choices=list(specialists), allow_multi=true)

    verified_calls = []
    for call in plan.calls:
        verdict = verifier.judge(
            query=query,
            chosen_module=call.name,
            args=call.args,
            alternatives=[n for n in specialists if n != call.name],
        )
        if verdict.kind == "accept":
            verified_calls.append(call)
        elif verdict.kind == "reroute":
            tracer.emit("mrkl.reroute", from_=call.name, to=verdict.suggested,
                        reason=verdict.reason)
            verified_calls.append(Call(name=verdict.suggested, args=verdict.args))
        else:
            tracer.emit("mrkl.refuse", module=call.name, reason=verdict.reason)

    results = {}
    for c in verified_calls:
        args = validate(c.args, specialists[c.name].schema)
        results[c.name] = specialists[c.name].handle(args)

    return llm.generate(
        prompt="Compose user-facing answer using expert outputs.",
        question=query, outputs=results,
    )

# Why this works: the verifier intercepts router mistakes BEFORE the wrong
# module is invoked, so calculator confusions and SQL-against-prose mismatches
# are corrected cheaply rather than producing junk that must be filtered later.
# Related: see `agent-as-judge`, `hybrid-symbolic-neural-routing`.

MODELS = {
    "cheap":  client("cheap-model"),
    "strong": client("strong-model"),
}

# Per-class binding: each class is pinned to a tier in advance,
# not chosen ad-hoc by the calling agent.
ROUTING = {
    "extract":   "cheap",
    "classify":  "cheap",
    "answer":    "strong",
}

function route(request):
    cls = classifier.classify(request)   # cheap-model call
    tier = ROUTING[cls]
    out = MODELS[tier].generate(request)

    # Optional cascade: only the cheap tier may escalate, and only
    # on low confidence, so we don't always-pay the strong tier.
    if tier == "cheap" and out.confidence < THRESHOLD:
        out = MODELS["strong"].generate(request)

    return out

