OPEN_SMALL = self_hosted_client("qwen-2.5-7b")     # inside boundary
OPEN_LARGE = self_hosted_client("llama-3.1-70b")   # inside boundary
FRONTIER   = hosted_client("claude-sonnet-4-6")    # crosses boundary

THRESHOLD  = 0.7

function route(request):
    # 1. Sensitivity classification BEFORE any model call.
    if pii_classifier.is_sensitive(request):
        out = OPEN_LARGE.generate(request)
        if out.confidence < THRESHOLD:
            # Sensitive + uncertain: refuse / degrade.
            # NEVER escalate sensitive traffic across the boundary.
            return degrade(request, reason="sensitive_uncertain")
        return out

    # 2. Insensitive easy: smallest local model.
    out = OPEN_SMALL.generate(request)
    if out.confidence >= THRESHOLD:
        return out

    # 3. Insensitive hard: escalate to frontier.
    return FRONTIER.generate(request)

# Related: pii-redaction
OPEN_SMALL = self_hosted_client("qwen-2.5-7b")
OPEN_LARGE = self_hosted_client("llama-3.1-70b")
FRONTIER   = hosted_client("claude-sonnet-4-6")
specialists = {"open_small": OPEN_SMALL, "open_large": OPEN_LARGE,
               "frontier":   FRONTIER}

function route(request):
    sens = pii_classifier.classify(request)    # {none | redactable | hard}
    if sens == "hard":
        return specialists["open_large"].generate(request)   # stays in-boundary

    if sens == "redactable":
        # Strip PII, keep a local re-attach map.
        scrubbed, mapping = pii_redactor.redact(request)
        tracer.emit("pii.redacted", spans=len(mapping))
        out = specialists["frontier"].generate(scrubbed)
        # Re-attach PII on the trusted host before the user sees the answer.
        return pii_redactor.reattach(out, mapping)

    # No PII: ordinary cost-cascade.
    out = specialists["open_small"].generate(request)
    if out.confidence >= 0.7:
        return out
    return specialists["frontier"].generate(request)

# Why this works: redactable requests get frontier quality without sending raw
# PII across the boundary, the local re-attach keeps the user-facing answer
# complete, and hard-sensitive requests stay home regardless of confidence.
# Related: see `pii-redaction`, `sovereign-inference-stack`.

