# Related: agent-as-judge, step-budget
function voted_judged_run(task, n=5, wall_budget_ms=8000):
    pending = {}
    for i in 1..n:
        pending[i] = spawn(lambda: llm.generate(task, temperature=0.7))

    samples = []
    deadline = now() + wall_budget_ms
    for handle in await_any(pending.values(), until=deadline):
        samples.append(handle.result)
        if now() >= deadline:
            break

    # Cancel stragglers — step-budget on the parallel fan.
    for i, h in pending.items():
        if not h.done:
            h.cancel()
            tracer.emit("sample.cancelled", index=i)

    if not samples:
        return abort("no_samples_in_budget")
    if len(samples) == 1:
        return samples[0]

    verdict = judge_agent.choose(
        question=task, candidates=samples,
        criteria=["correctness", "clarity", "completeness"],
    )
    tracer.emit("voted.judged", picked=verdict.index, rationale=verdict.rationale,
                samples_kept=len(samples))
    return verdict.answer

# Why this works: voting catches unlucky samples, the judge resolves ties with
# a reasoned pick instead of majority count, and the wall-clock cap with
# cancellation prevents one slow sample from dragging the whole turn.
# Related: see `agent-as-judge`, `best-of-n`, `step-budget`.

