    Step(name="extract",   prompt=EXTRACT_PROMPT,   schema=ExtractOut),
    Step(name="classify",  prompt=CLASSIFY_PROMPT,  schema=ClassifyOut),
    Step(name="summarize", prompt=SUMMARIZE_PROMPT, schema=SummaryOut),
]

function run(input):
    value = input
    for step in STEPS:
        for attempt in 1..MAX_RETRIES:
            raw = llm.generate(step.prompt, input=value)
            try:
                value = validate(raw, step.schema)
                break               # this step is done
            except ValidationError:
                continue
        else:
            return abort(step.name) # never reach downstream steps
    return value

LANES = {
    "command": deterministic_action_handler,   # no LLM in the loop
    "agent":   multi_step_agent,               # tool-using agent
    "chat":    plain_chat_model,               # no tools
}

function route(request):
    # Cheapest model available — classification only.
    label = classifier.classify(
        request,
        labels=list(LANES.keys()),
    )
    handler = LANES.get(label, LANES["chat"])   # safe default
    return handler(request)

# Related: verification-of-route-choice, disambiguation
LANES = {
    "command": deterministic_action_handler,
    "agent":   multi_step_agent,
    "chat":    plain_chat_model,
}

function route(request):
    pick = classifier.classify(request, labels=list(LANES))

    verdict = verifier.judge(
        request=request, picked=pick.label,
        confidence=pick.confidence,
        alternatives=[l for l in LANES if l != pick.label],
    )

    if verdict.kind == "accept":
        chosen = pick.label
    elif verdict.kind == "reroute":
        tracer.emit("route.reroute", from_=pick.label, to=verdict.suggested,
                    reason=verdict.reason)
        chosen = verdict.suggested
    elif verdict.kind == "ambiguous":
        # Do NOT guess. Ask the user.
        question = disambiguator.compose(
            request=request, candidates=verdict.candidates,
        )
        tracer.emit("route.disambiguate", candidates=verdict.candidates)
        return ask_user(question)
    else:
        return human_handoff(request, reason=verdict.reason)

    specialists = LANES
    return specialists[chosen](request)

# Why this works: the verifier converts low classifier confidence into either
# a corrected route or a user-facing question, so genuinely ambiguous requests
# get clarified instead of being silently routed to whichever lane scored 0.51.
# Related: see `agent-as-judge`, `disambiguation`.

# --- offline: mine traces and promote stable clusters ---
def promotion_pass():
    for cluster in recurrence_mine(trace_store, min_count=10):
        rule = author_rule(cluster)                # DMN row / code path from the observed trajectory
        replay = replay_validate(rule, cluster.traces)
        if replay.divergence == 0:
            rule_engine.deploy(rule, guard=cluster.signature,
                               provenance=cluster.trace_ids)   # rule -> its evidence
        else:
            review_queue.add(cluster, replay)      # human decides; never auto-ship on divergence

# --- runtime: rule short-circuits the model ---
def handle(case):
    rule = rule_engine.match(case)                 # guard must match the mined signature
    if rule:
        return rule.evaluate(case)                 # deterministic, auditable, cheap
    result = agent.solve(case)                     # discovery path for the residue
    trace_store.log(case, result)                  # feeds the next promotion pass
    return result
